import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { contentApi } from '../../services/api';
import { useNotify } from '../../hooks/useNotify';
import '../Admin.css';

const INITIAL = {
  title: '',
  description: '',
  thumbnail: '',
  content: '',
  featured: false,
  trending: false,
};

export default function UploadBlog() {
  const [form, setForm] = useState(INITIAL);
  const [saving, setSaving] = useState(false);
  const navigate = useNavigate();
  const notify = useNotify();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      await contentApi.create({
        type: 'blog',
        title: form.title,
        description: form.description,
        thumbnail: form.thumbnail,
        content: form.content,
        featured: form.featured,
        trending: form.trending,
      });
      navigate('/admin/blogs');
    } catch (err) {
      setError(err.message);
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="dash-page">
      <div className="dash-page__header">
        <div>
          <Link to="/admin/blogs" className="dash-breadcrumb">← Back to Blogs</Link>
          <h1>Upload Blog</h1>
          <p>Publish a new blog post on Very Direct</p>
        </div>
      </div>

      <form className="upload-form" onSubmit={handleSubmit}>
        {error && <div className="form-error">{error}</div>}

        <div className="upload-form__grid">
          <div className="upload-form__main">
            <div className="upload-form__section">
              <h2>Blog Content</h2>
              <label>
                Title <span className="required">*</span>
                <input
                  value={form.title}
                  onChange={(e) => setForm({ ...form, title: e.target.value })}
                  placeholder="Enter blog title"
                  required
                />
              </label>
              <label>
                Short Description
                <input
                  value={form.description}
                  onChange={(e) => setForm({ ...form, description: e.target.value })}
                  placeholder="Brief summary shown in listings"
                />
              </label>
              <label>
                Content <span className="required">*</span>
                <textarea
                  value={form.content}
                  onChange={(e) => setForm({ ...form, content: e.target.value })}
                  placeholder="Write your blog content here. Use blank lines between paragraphs."
                  rows={14}
                  required
                />
              </label>
            </div>
          </div>

          <div className="upload-form__side">
            <div className="upload-form__section">
              <h2>Cover Image</h2>
              <label>
                Thumbnail URL
                <input
                  value={form.thumbnail}
                  onChange={(e) => setForm({ ...form, thumbnail: e.target.value })}
                  placeholder="https://example.com/cover.jpg"
                />
              </label>
              {form.thumbnail && (
                <img src={form.thumbnail} alt="Preview" className="upload-form__preview" />
              )}
            </div>

            <div className="upload-form__section">
              <h2>Settings</h2>
              <label className="upload-checkbox">
                <input
                  type="checkbox"
                  checked={form.featured}
                  onChange={(e) => setForm({ ...form, featured: e.target.checked })}
                />
                Mark as Featured
              </label>
              <label className="upload-checkbox">
                <input
                  type="checkbox"
                  checked={form.trending}
                  onChange={(e) => setForm({ ...form, trending: e.target.checked })}
                />
                Mark as Trending
              </label>
            </div>

            <button type="submit" className="btn btn-primary upload-form__submit" disabled={saving}>
              {saving ? 'Publishing...' : 'Publish Blog'}
            </button>
          </div>
        </div>
      </form>
    </div>
  );
}
